@AbapCatalog.sqlViewName: 'ZV_SALESORD'
@AbapCatalog.compiler.compareFilter: true
@AccessControl.authorizationCheck: #NOT_REQUIRED
@EndUserText.label: 'Sales Order CDS View'
define root view entity ZI_SalesOrder
  as select from zsales_order
{
  key order_id        as OrderId,
      customer_id     as CustomerId,
      order_date      as OrderDate,
      total_amount    as TotalAmount,
      status          as Status
}

// Behavior Definition (managed)
managed implementation in class ZBP_SalesOrder unique;

define behavior for ZI_SalesOrder alias SalesOrder
persistent table zsales_order
lock master
{
  create; update; delete;
  field ( readonly ) OrderId;
  validation validateDates on save { field OrderDate; }
}

// Service Definition
define service ZSD_SalesOrder { expose ZI_SalesOrder as SalesOrder; }

