" === MANAGED RAP BDEF (SAP handles all DB ops) ===
managed implementation in class ZBP_LeaveRequest unique;
define behavior for ZI_LeaveRequest alias LeaveRequest
persistent table zleave_request
lock master
draft table zdt_leave_request
{
  create; update; delete;
  field ( mandatory ) EmployeeId, StartDate, EndDate;
  field ( readonly )  RequestId, Status;
  validation validateDates    on save { field StartDate, EndDate; }
  determination setInitStatus  on save { create; }
  action approveRequest result [1] $self;
}

" === UNMANAGED RAP BDEF (developer handles DB ops) ===
unmanaged implementation in class ZBP_Customer unique;
define behavior for ZI_Customer alias Customer
lock master
{
  create; update; delete;
  field ( mandatory ) CustomerName, Country;
}

" === UNMANAGED: FOR MODIFY with BAPI call ===
METHOD create FOR MODIFY
    IMPORTING entities FOR CREATE Customer.
  LOOP AT entities INTO DATA(ls_cust).
    CALL FUNCTION 'BAPI_CUSTOMER_CREATEFROMDATA1'
      EXPORTING name1 = ls_cust-CustomerName
      IMPORTING kunnr = DATA(lv_kunnr)
      TABLES    return = DATA(lt_return).
    IF lv_kunnr IS NOT INITIAL.
      APPEND VALUE #( %cid = ls_cust-%cid
        %key-CustomerId = lv_kunnr ) TO mapped-customer.
    ELSE.
      APPEND VALUE #( %cid = ls_cust-%cid ) TO failed-customer.
    ENDIF.
  ENDLOOP.
ENDMETHOD.

